#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n,q;    cin >> n >> q;    vll a(n);    for(int i=0; i<n; i++) cin >> a[i];    ll sum=0;    vll prefix_sum(n+1, 0);    for(int i=0; i<n; i++) {                prefix_sum[i+1] = prefix_sum[i] + a[i];    }    sum=prefix_sum[n];    while(q--){                int l,r,k;        cin >> l >> r >> k;        ll old_sum= prefix_sum[r] -(l > 0? prefix_sum[l-1] : 0);        ll new_sum=sum-old_sum + (r-l+1)*k;        if(new_sum%2!=0) cout << "YES\n";        else cout << "NO\n";      }              } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}